  window.TTS_AUDIO['Living things grow and change. They need food, water, and air. Animals eat. Plants make food. A rock is nonliving. Now show what you know!'] = base + 'grade-1-living-things-grow-and-change-they-need-16fcc0-16fcc09e.wav';
  window.TTS_AUDIO['A force is a push or a pull. A big force moves a thing far. Force can change a path. Gravity pulls everything down. Now show what you know!'] = base + 'grade-1-a-force-is-a-push-or-a-768265-7682658c.wav';
  window.TTS_AUDIO['Each year has four seasons. Summer is hot. Winter is cold. Spring brings rain and flowers. Fall is windy. Leaves drop. Now show what you know!'] = base + 'grade-1-each-year-has-four-seasons-summer-is-c91e83-c91e832f.wav';
